"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["39722"],{122778(a){a.exports=JSON.parse('{"tag":{"label":"boat","permalink":"/dst-api-webdocs/docs/tags/boat","allTagsPath":"/dst-api-webdocs/docs/tags","count":49,"items":[{"id":"game-scripts/components/anchor","title":"Anchor","description":"Manages the raising and lowering state of an anchor attached to a boat, handling drag physics, animation timing, and multiplayer coordination via sailor tasks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/anchor"},{"id":"game-scripts/prefabs/anchor","title":"Anchor","description":"A deployable boat accessory that prevents vessel movement and interacts with water physics and environmental systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/anchor"},{"id":"game-scripts/prefabs/boat_bumper_kit","title":"Boat Bumper Kit","description":"Creates and configures deployable bumper prefabs for boats, handling health, repairs, destruction, and interaction with boat ring systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat_bumper_kit"},{"id":"game-scripts/prefabs/boat_leak","title":"Boat Leak","description":"Prefab that represents a leak on boats, plugging when entities block it and launching items when plugged long enough.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat_leak"},{"id":"game-scripts/prefabs/boat_magnet","title":"Boat Magnet","description":"A deployable structure component that enables boat magnet functionality by pairing with a beacon and responding to beacon state changes via the state graph.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat_magnet"},{"id":"game-scripts/prefabs/boat_magnet_beacon","title":"Boat Magnet Beacon","description":"Manages the beacon that pairs with a boat magnet to control magnet movement when placed on a boat.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat_magnet_beacon"},{"id":"game-scripts/prefabs/boat_water_fx","title":"Boat Water Fx","description":"Creates a non-persistent visual effect for boat wake trails beneath the water surface.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boat_water_fx"},{"id":"game-scripts/components/boatai","title":"Boatai","description":"Controls a boat\'s AI behavior by scanning for nearby sail-raised vessels and adjusting its own sail to follow them.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatai"},{"id":"game-scripts/components/boatcannonuser","title":"Boatcannonuser","description":"Manages the state and synchronization of boat cannon aiming for a player entity, handling client-side aiming visuals and server-side cannon assignment.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatcannonuser"},{"id":"game-scripts/components/boatdrag","title":"Boatdrag","description":"Calculates and applies drag and velocity modifiers to watercraft entities during movement.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatdrag"},{"id":"game-scripts/components/boatdrifter","title":"Boatdrifter","description":"Manages the physics and movement state of a boat entity, including drift detection, physics activation/deactivation, and wake test lifecycle.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatdrifter"},{"id":"game-scripts/components/boatleak","title":"Boatleak","description":"Manages visual, audio, and state transitions for boat leaks and repairs in DST, including plugged/unplugged states, repair timers, and integration with HullHealth for dynamic leak tracking.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatleak"},{"id":"game-scripts/components/boatmagnet","title":"Boatmagnet","description":"Manages the magnetic attraction behavior of a boat toward a paired beacon, calculating forces and velocity to pull the boat toward the beacon\'s location while avoiding collisions and adapting to motion.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatmagnet"},{"id":"game-scripts/components/boatmagnetbeacon","title":"Boatmagnetbeacon","description":"Coordinates beacon behavior for boat magnet pairs, including pairing/unpairing logic, beacon activation state, and platform (boat) tracking.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatmagnetbeacon"},{"id":"game-scripts/widgets/boatmeter","title":"Boatmeter","description":"Displays a boat\'s health status and leak state in the UI, updating dynamically during gameplay.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/boatmeter"},{"id":"game-scripts/components/boatpatch","title":"Boatpatch","description":"Assigns the `boat_patch` tag to an entity and provides basic patch type tracking for boat-related environmental patches.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatpatch"},{"id":"game-scripts/prefabs/boatpatch","title":"Boatpatch","description":"A game entity component that enables repairs to damaged boats using consumable patch materials (wood or kelp), providing health restoration and related functional behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatpatch"},{"id":"game-scripts/prefabs/boatrace_checkpoint_indicator","title":"Boatrace Checkpoint Indicator","description":"Acts as a visual marker that rotates to point toward the nearest race checkpoint during a boat race, and triggers music playback for nearby players.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/boatrace_checkpoint_indicator"},{"id":"game-scripts/brains/boatrace_primematebrain","title":"Boatrace Primematebrain","description":"Implements the AI behavior for the prime mate in boat races, prioritizing buoy tossing, leak repair, fire suppression, and rowing to keep the boat functional and competitive.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/boatrace_primematebrain"},{"id":"game-scripts/components/boatracecrew","title":"Boatracecrew","description":"Manages a crew of entities assigned to a boat, tracking members, handling their life-cycle events, and supporting network serialization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatracecrew"},{"id":"game-scripts/components/boatring","title":"Boatring","description":"Manages rotation behavior and bumper collision detection for a boat entity in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatring"},{"id":"game-scripts/components/boatringdata","title":"Boatringdata","description":"Stores and synchronizes visual ring configuration data for boat-related effects, including radius, segment count, and rotation state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatringdata"},{"id":"game-scripts/components/boatrotator","title":"Boatrotator","description":"Manages the rotation direction synchronization between a character entity and its current boat platform.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boatrotator"},{"id":"game-scripts/components/boattrailmover","title":"Boattrailmover","description":"Manages movement and trajectory tracking for a boat entity in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/boattrailmover"},{"id":"game-scripts/prefabs/burnable_locator_medium","title":"Burnable Locator Medium","description":"A non-physical, boat-anchored locator entity that triggers fire damage on its parent boat while smoldering or burning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/burnable_locator_medium"},{"id":"game-scripts/components/cookiecutterdrill","title":"CookieCutterDrill","description":"Manages the drilling progression for a cookie-cutter boat leak repair mechanism, handling animation state and damage application upon completion.","permalink":"/dst-api-webdocs/docs/game-scripts/components/cookiecutterdrill"},{"id":"game-scripts/components/crewmember","title":"Crewmember","description":"Manages the rowing behavior and boat association for entities acting as crew members on boats.","permalink":"/dst-api-webdocs/docs/game-scripts/components/crewmember"},{"id":"game-scripts/components/expertsailor","title":"Expertsailor","description":"Controls configuration values that modify boat sailing physics and anchor behavior for a boat entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/expertsailor"},{"id":"game-scripts/prefabs/gnarwail","title":"Gnarwail","description":"Controls the behavior, state management, and interaction logic for the Gnarwail entity, including horn combat, loyalty mechanics, and formation following behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gnarwail"},{"id":"game-scripts/brains/gnarwailbrain","title":"Gnarwailbrain","description":"AI brain controller for the Gnarwail creature that manages navigation, combat, trading, tossing, and feeding behaviors in a water-centric world.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/gnarwailbrain"},{"id":"game-scripts/components/hull","title":"Hull","description":"Manages visual and logical attachment of boat-related accessories (plank, lip) and handles entity attachment offsets during boat placement.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hull"},{"id":"game-scripts/components/hullhealth","title":"Hullhealth","description":"Manages hull integrity and leak damage for boats, handling collision impacts, degradation over time, and dynamic leak indicators.","permalink":"/dst-api-webdocs/docs/game-scripts/components/hullhealth"},{"id":"game-scripts/components/mast","title":"Mast","description":"Manages sail state and forces for a boat mast, including furling/unfurling mechanics, physics interaction with the boat, and animation synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mast"},{"id":"game-scripts/prefabs/mast","title":"Mast","description":"Manages mast structures for boats, including sail deployment, fuel-powered lighting upgrades (lamp), lightning rod upgrades, and destruction behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mast"},{"id":"game-scripts/components/oar","title":"Oar","description":"Handles rowing mechanics for boats, applying directional force and managing rowing success/fail behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oar"},{"id":"game-scripts/components/placer","title":"Placer","description":"Manages placement positioning, orientation, and visual feedback for deployable structures and items in the game world, including support for axis-aligned placement and boat edge snapping.","permalink":"/dst-api-webdocs/docs/game-scripts/components/placer"},{"id":"game-scripts/prefabs/primemate","title":"Primemate","description":"A monkey-like NPC that can command boats, fight with melee weapons, and coordinate with other monkeys in combat.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/primemate"},{"id":"game-scripts/brains/primematebrain","title":"Primematebrain","description":"Implements AI behavior for the Primemate character, managing actions like boat rowing, leak repair, fleeing, wandering, chasing, and abandoning a boat when it sinks.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/primematebrain"},{"id":"game-scripts/prefabs/rudder","title":"Rudder","description":"A visual indicator prefab attached to boat masts that displays the current heading direction, used for orientation and navigation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rudder"},{"id":"game-scripts/prefabs/sewing_tape","title":"Sewing Tape","description":"A stackable inventory item used for repairing boats via the sewing system, providing a fixed amount of repair value.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sewing_tape"},{"id":"game-scripts/stategraphs/SGanchor","title":"Sganchor","description":"Manages the state machine for an anchor entity\u2019s tethered state transitions (raising/lowering) and visual/animation synchronization based on water depth.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGanchor"},{"id":"game-scripts/stategraphs/SGboat","title":"Sgboat","description":"Controls the life cycle and visual/audio behavior of a boat entity during construction, idle, damage, and sinking phases in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGboat"},{"id":"game-scripts/stategraphs/SGboat_ice","title":"Sgboat Ice","description":"Manages the lifecycle and state transitions of an ice-based boat entity, including placement, damage\u54CD\u5E94, sinking, and destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGboat_ice"},{"id":"game-scripts/prefabs/steeringwheel","title":"Steeringwheel","description":"Manages the logic for a boat\'s steering wheel, including player interaction, burning effects, and looting upon destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/steeringwheel"},{"id":"game-scripts/components/steeringwheeluser","title":"Steeringwheeluser","description":"Manages a character\'s interaction with a steering wheel to control boat movement, including state transitions and rudder direction updates.","permalink":"/dst-api-webdocs/docs/game-scripts/components/steeringwheeluser"},{"id":"game-scripts/prefabs/walkingplank","title":"Walkingplank","description":"Creates a floating platform prefab attached to boats that can be haunted by Wickerbeast attacks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/walkingplank"},{"id":"game-scripts/brains/waveyjoneshandbrain","title":"Waveyjoneshandbrain","description":"Controls the behavior of Wavey Jones\' hand entity by selecting and performing repair-related actions on boat components based on current conditions and player sanity.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/waveyjoneshandbrain"},{"id":"game-scripts/prefabs/winch","title":"Winch","description":"Manages the mechanical winch structure that can lower and raise a claw to salvage submerged objects, while interacting with boat physics and inventory systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winch"},{"id":"game-scripts/prefabs/yotd_boats","title":"Yotd Boats","description":"Defines the data and logic for the Year of the Dragon Boat (YOTD) prefabs in DST, including the boat body, deployable kits, item packs, and AI shadowboat variants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotd_boats"}],"unlisted":false}}')}}]);